section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/risk-assessment.json",
  "title": "Risk Assessment",
  "type": "object",
  "required": [
    "artefact_id",
    "risks",
    "matrix",
    "top_quartile",
    "review_cycle",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "risks": {
      "type": "array",
      "description": "rows: {id, name, category, likelihood:1-5, impact:1-5, score, owner, mitigation}",
      "minItems": 1
    },
    "matrix": {
      "type": "object",
      "description": "5x5 grid placement"
    },
    "top_quartile": {
      "type": "array",
      "description": "filtered list of score\u226516 risks",
      "minItems": 1
    },
    "review_cycle": {
      "type": "string",
      "description": "next review ISO date",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "risk-assessment-2026-05-23",
  "risks": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "matrix": {
    "key": "value"
  },
  "top_quartile": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "review_cycle": "draft",
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
